onClick:
{{
(() => {

    if (!inpID_Avance_AAF.text) {
        showAlert("Debe indicar el ID del Avance.", "warning");
        return;
    }

    if (!inpID_FC_AAF.text) {
        showAlert("Debe indicar el ID de la Factura.", "warning");
        return;
    }

    if (
        Number((inpMontoAplicadoAAF.text || "0").replace(/,/g,"")) <= 0
    ) {
        showAlert("Debe indicar un monto válido.", "warning");
        return;
    }

    qryAAFAplicar.run()

    .then(() =>

        Promise.all([

            resetWidget("inpID_Avance_AAF", true),
            resetWidget("inpID_FC_AAF", true),
            resetWidget("inpMontoAplicadoAAF", true)

        ])

    )

    .then(() => {

        showAlert(
            "Avance aplicado correctamente.",
            "success"
        );

    })

    .catch((e) => {

        showAlert(
            e.message,
            "error"
        );

    });

})()
}}
